import { useState } from "react";
import { motion } from "framer-motion";
import { Card, CardContent } from "../../components/ui/card";
import { Button } from "../../components/ui/button";
import { Input } from "../../components/ui/input";

export default function AdminPanel() {
  const [page, setPage] = useState("dashboard");
  const [foodName, setFoodName] = useState("");
  const [price, setPrice] = useState("");

  const addFood = () => {
    const foods = JSON.parse(localStorage.getItem("foods") || "[]");
    foods.push({ foodName, price });
    localStorage.setItem("foods", JSON.stringify(foods));
    setFoodName("");
    setPrice("");
    alert("Food Added Successfully");
  };

  const Dashboard = () => (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
      <h1 className="text-3xl font-bold mb-6">Admin Dashboard</h1>
      <div className="grid grid-cols-2 gap-4">
        <Button onClick={() => setPage("addFood")}>Add Food</Button>
        <Button onClick={() => setPage("viewFoods")}>View Foods</Button>
        <Button onClick={() => setPage("orders")}>Orders</Button>
        <Button onClick={() => setPage("bookings")}>Bookings</Button>
      </div>
    </motion.div>
  );

  const AddFood = () => (
    <motion.div initial={{ x: 100, opacity: 0 }} animate={{ x: 0, opacity: 1 }}>
      <Card className="p-4">
        <CardContent>
          <h2 className="text-2xl mb-4">Add Food</h2>
          <Input
            placeholder="Food Name"
            value={foodName}
            onChange={(e) => setFoodName(e.target.value)}
            className="mb-3"
          />
          <Input
            placeholder="Price"
            value={price}
            onChange={(e) => setPrice(e.target.value)}
            className="mb-3"
          />
          <Button onClick={addFood}>Save Food</Button>
        </CardContent>
      </Card>
    </motion.div>
  );

  const ViewFoods = () => {
    const foods = JSON.parse(localStorage.getItem("foods") || "[]");
    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
        <h2 className="text-2xl mb-4">Food List</h2>
        {foods.map((food, index) => (
          <Card key={index} className="mb-2 p-3">
            {food.foodName} - KES {food.price}
          </Card>
        ))}
      </motion.div>
    );
  };

  const Orders = () => (
    <div>
      <h2 className="text-2xl">Orders Page</h2>
      <p>Food orders will appear here.</p>
    </div>
  );

  const Bookings = () => (
    <div>
      <h2 className="text-2xl">Bookings Page</h2>
      <p>Room & Event bookings will appear here.</p>
    </div>
  );

  return (
    <div className="p-6">
      {page === "dashboard" && <Dashboard />}
      {page === "addFood" && <AddFood />}
      {page === "viewFoods" && <ViewFoods />}
      {page === "orders" && <Orders />}
      {page === "bookings" && <Bookings />}
      <Button className="mt-6" variant="secondary" onClick={() => setPage("dashboard")}>
        Back to Dashboard
      </Button>
    </div>
  );
}
